import json, sys
data = json.load(sys.stdin)
baseline = json.load(open('baseline-packages.json'))

def extract(d):
    result = {}
    for p in d['projects']:
        name = p['path'].split('/')[-1]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                key = (name, fw['framework'], pkg['id'])
                result[key] = pkg['resolvedVersion']
    return result

before = extract(baseline)
after = extract(data)

all_keys = sorted(set(before.keys()) | set(after.keys()))
changes = []
unchanged = []
for k in all_keys:
    b = before.get(k)
    a = after.get(k)
    if b != a:
        changes.append((k, b, a))
    else:
        unchanged.append((k, a))

print('=== CHANGES ===')
if changes:
    for (proj, fw, pkg), b, a in changes:
        print(f'{proj} | {fw} | {pkg} | {b} -> {a}')
else:
    print('None')

print(f'\n=== UNCHANGED: {len(unchanged)} packages ===')"

